from langgraph.graph import StateGraph, END
from langgraph.types import Command
from langchain_anthropic import ChatAnthropic
from typing import TypedDict, Annotated, Literal
import operator

haiku  = ChatAnthropic(model="claude-haiku-4-5-20251001")
sonnet = ChatAnthropic(model="claude-sonnet-5")

class P2PState(TypedDict):
    task: str
    proposal: str
    critique: str
    fact_check: str
    final: str
    round: int
    errors: Annotated[list[str], operator.add]

MAX_ROUNDS = 3

def agent_a_drafter(state: P2PState) -> Command[Literal["agent_b", "agent_d"]]:
    """Drafts a proposal and sends to critic (B) and fact-checker (C) via B first."""
    try:
        resp = sonnet.invoke([
            {"role": "system", "content": "Draft a clear, structured proposal for the given task."},
            {"role": "user",   "content": state["task"]},
        ])
        proposal = resp.content
        # After drafting, send to critic
        return Command(
            goto="agent_b",
            update={"proposal": proposal, "round": state["round"] + 1},
        )
    except Exception as exc:
        return Command(goto=END, update={"errors": [f"drafter:{exc}"]})

def agent_b_critic(state: P2PState) -> Command[Literal["agent_c", "agent_d"]]:
    """Critiques the proposal and either iterates or forwards to fact-checker."""
    if state["round"] >= MAX_ROUNDS:
        return Command(goto="agent_d", update={})

    resp = haiku.invoke([
        {"role": "system", "content": "Critique this proposal. If it is good enough, say APPROVE. Otherwise give specific improvements."},
        {"role": "user",   "content": state["proposal"]},
    ])
    critique = resp.content

    if "APPROVE" in critique:
        return Command(goto="agent_c", update={"critique": critique})
    # Critique not approved — forward critique to fact-checker concurrently
    return Command(goto="agent_c", update={"critique": critique})

def agent_c_factchecker(state: P2PState) -> Command[Literal["agent_d"]]:
    """Checks factual accuracy and sends to synthesizer."""
    resp = haiku.invoke([
        {"role": "system", "content": "Check the factual accuracy of this proposal. Note any errors or unverifiable claims."},
        {"role": "user",   "content": state["proposal"]},
    ])
    return Command(goto="agent_d", update={"fact_check": resp.content})

def agent_d_synthesizer(state: P2PState) -> dict:
    """Synthesizes proposal + critique + fact-check into final output."""
    context = (
        f"Original proposal:\n{state['proposal']}\n\n"
        f"Critique:\n{state['critique']}\n\n"
        f"Fact-check:\n{state['fact_check']}"
    )
    resp = sonnet.invoke([
        {"role": "system", "content": "Synthesize the proposal, critique, and fact-check into an improved final response."},
        {"role": "user",   "content": context},
    ])
    return {"final": resp.content}

def safe_goto(
    state: P2PState,
    intended: str,
    fallback: str = "agent_d",
) -> str:
    """Route to intended destination only if round limit not exceeded."""
    if state["round"] >= MAX_ROUNDS:
        return fallback
    return intended

def agent_b_critic_safe(state: P2PState) -> Command:
    if state["round"] >= MAX_ROUNDS:
        # Hard stop — skip further critique, go to synthesizer
        return Command(goto="agent_d", update={"critique": "max_rounds_reached"})

    resp = haiku.invoke([
        {"role": "system", "content": "Critique the proposal briefly."},
        {"role": "user",   "content": state["proposal"]},
    ])
    next_node = safe_goto(state, "agent_c")
    return Command(goto=next_node, update={"critique": resp.content, "round": state["round"] + 1})

class VotedState(P2PState):
    votes: Annotated[list[str], operator.add]   # "approve" or "reject"

QUORUM = 2   # number of approvals needed to terminate early

def agent_b_voting_critic(state: VotedState) -> Command:
    if state["round"] >= MAX_ROUNDS:
        return Command(goto="agent_d", update={"votes": ["approve"]})

    resp = haiku.invoke([
        {"role": "system", "content": (
            "Critique this proposal. End your response with either "
            "VOTE:APPROVE if it is ready, or VOTE:REJECT if it needs work."
        )},
        {"role": "user", "content": state["proposal"]},
    ])
    vote = "approve" if "VOTE:APPROVE" in resp.content else "reject"
    approvals = sum(1 for v in state["votes"] if v == "approve") + (1 if vote == "approve" else 0)

    if approvals >= QUORUM:
        # Quorum reached — skip further critique
        return Command(goto="agent_d", update={"critique": resp.content, "votes": [vote]})
    return Command(goto="agent_c", update={"critique": resp.content, "votes": [vote]})
